def count_paths(grid):
    if not grid or not grid[0]:
        return 0
    R, C = len(grid), len(grid[0])
    if grid[0][0] or grid[R - 1][C - 1]:
        return 0
    # row vector; dp[c] = number of paths reaching current cell (r, c).
    # Moves into (r, c) come from (r, c-1) [right], (r-1, c) [down],
    # and (r-1, c-1) [diagonal]. Process rows top-to-bottom, columns
    # left-to-right, folding the previous row into a single rolling array.
    dp = [0] * C
    for r in range(R):
        diag = 0  # value of dp[c-1] from the PREVIOUS row, i.e. (r-1, c-1)
        for c in range(C):
            up = dp[c]          # (r-1, c), still holds previous row's value
            if grid[r][c]:
                cur = 0
            elif r == 0 and c == 0:
                cur = 1
            else:
                left = dp[c - 1] if c > 0 else 0  # (r, c), already updated this row
                cur = left + up + diag
            diag = up            # becomes (r-1, c-1) for the next column
            dp[c] = cur
    return dp[C - 1]

