def count_paths(grid):
    if not grid or not grid[0]:
        return 0
    rows = len(grid)
    cols = len(grid[0])
    # memo[r][c] = number of strictly increasing paths from (r,c) to bottom-right
    memo = [[None] * cols for _ in range(rows)]
    target = (rows - 1, cols - 1)
    # iterative DFS with explicit stack; post-order accumulation
    stack = [(0, 0, False)]
    while stack:
        r, c, processed = stack.pop()
        if memo[r][c] is not None:
            continue
        if (r, c) == target:
            memo[r][c] = 1
            continue
        if not processed:
            # collect valid (strictly increasing) neighbors
            neighbors = []
            for dr, dc in ((0, 1), (1, 0)):
                nr, nc = r + dr, c + dc
                if nr < rows and nc < cols and grid[nr][nc] > grid[r][c]:
                    neighbors.append((nr, nc))
            stack.append((r, c, True))
            for nr, nc in neighbors:
                if memo[nr][nc] is None:
                    stack.append((nr, nc, False))
        else:
            total = 0
            for dr, dc in ((0, 1), (1, 0)):
                nr, nc = r + dr, c + dc
                if nr < rows and nc < cols and grid[nr][nc] > grid[r][c]:
                    total += memo[nr][nc] if memo[nr][nc] is not None else 0
            memo[r][c] = total
    return memo[0][0] if memo[0][0] is not None else 0

