def count_paths(grid):
    if not grid or not grid[0]:
        return 0
    R, C = len(grid), len(grid[0])
    # dp[r][c] = number of strictly increasing right/down paths from (0,0) to (r,c)
    # Recurrence over the partial order of the grid (cells reachable only from up/left):
    #   dp[r][c] = [from above] * (grid[r-1][c] < grid[r][c])
    #            + [from left]  * (grid[r][c-1] < grid[r][c])
    # with dp[0][0] = 1 as the empty-prefix base case. The strict-increase
    # constraint is enforced edge-wise, so the count is exact.
    dp = [[0] * C for _ in range(R)]
    dp[0][0] = 1
    for r in range(R):
        for c in range(C):
            if r == 0 and c == 0:
                continue
            total = 0
            if r > 0 and grid[r - 1][c] < grid[r][c]:
                total += dp[r - 1][c]
            if c > 0 and grid[r][c - 1] < grid[r][c]:
                total += dp[r][c - 1]
            dp[r][c] = total
    return dp[R - 1][C - 1]

def num_gap_subseq(s, t):
    n, m = len(s), len(t)
    # dp[j] over t prefix length; need non-adjacent indices.
    # ways[j] = number of ways to match t[:j] using some chosen indices, keyed by whether
    # we track last used index adjacency. Use 2D over positions.
    from functools import lru_cache
    import sys
    sys.setrecursionlimit(10000)

    @lru_cache(maxsize=None)
    def rec(i, j, prev_used):
        # i: index in s, j: index in t, prev_used: True if index i-1 was chosen
        if j == m:
            return 1
        if i == n:
            return 0
        total = rec(i + 1, j, False)  # skip s[i]
        if s[i] == t[j] and not prev_used:
            total += rec(i + 1, j + 1, True)  # choose s[i]
        return total

    return int(rec(0, 0, False))

