def num_gap_subseq(s, t):
    n, m = len(s), len(t)
    if m == 0:
        return 1
    # prefix[j][i] = sum_{k=1..i} f[k][j], where f[k][j] counts subsequences
    # equal to t[:j] whose last chosen index is k-1 (0-based), with the
    # non-adjacency constraint (consecutive chosen indices differ by >= 2).
    prefix = [[0] * (n + 1) for _ in range(m + 1)]
    for j in range(1, m + 1):
        for i in range(1, n + 1):
            if s[i - 1] == t[j - 1]:
                if j == 1:
                    f = 1
                else:
                    idx = i - 2
                    f = prefix[j - 1][idx] if idx >= 0 else 0
            else:
                f = 0
            prefix[j][i] = prefix[j][i - 1] + f
    return prefix[m][n]

