def num_gap_subseq(s, t):
    m = len(t)
    base = [1] + [0] * m          # A[0] = empty subsequence (last index = -infinity)
    A = base[:]                   # A_{i-1}: matchings with last chosen index <= i-1
    prev2 = base[:]               # A_{i-2}: matchings with last chosen index <= i-2
    for c in s:
        newA = A[:]               # not choosing position i: carry A_{i-1} forward
        for j in range(1, m + 1):
            if c == t[j - 1]:     # choosing i for t[j-1]; previous pick must be <= i-2 (gap >= 2)
                newA[j] += prev2[j - 1]
        prev2 = A                 # for next step, A_{(i+1)-2} = A_{i-1}
        A = newA
    return A[m]

